section.script:
'use strict';
(async function() {
  // --- CONFIG ---
  const feeds = [
    "https://www.therundown.ai/feed.xml",
    "https://techcrunch.com/feed/",
    "https://www.theverge.com/rss/index.xml",
    "https://www.technologyreview.com/feed/",
    "https://arstechnica.com/feed/",
    "https://blog.google/technology/ai/rss/",
    "https://rss.arxiv.org/rss/cs.AI",
    "https://openai.com/feed.xml",
    "https://www.marktechpost.com/feed/",
    "https://hnrss.org/frontpage?points=100",
    "https://blog.bytebytego.com/feed",
    "https://github.blog/feed/"
  ];
  const ALLOWED_DOMAINS = ["github.com", "rss.arxiv.org", "blog.bytebytego.com", "hnrss.org", "marktechpost.com", "openai.com", "blog.google", "therundown.ai","techcrunch.com","theverge.com","technologyreview.com","arstechnica.com"];
  const BLACKLIST = ["car","cars","bmw","review","reviews","gear","automotive","auto","motor","motors","vehicle","vehicles","fashion","lifestyle","movie","tv","sports"];
  const KEYWORDS = ['ai','security','cyber','vulnerability','exploit','ransomware','malware','cve','cloud','kubernetes','kernel','firmware','privacy','encryption','iot','edge','chip','cpu','gpu'];
  const TARGET_COUNT = 5;

  // --- CACHE SETTINGS ---
  const CACHE_KEY = 'tech_feed_cache';
  const CACHE_TTL_MS = 1000 * 60 * 30; // 30 minutes

  // --- DOM SELECTOR & FALLBACK ---
  const listSelector = '#research .blog-list';
  const listEl = document.querySelector(listSelector);
  const fallbackHTML = `


      Bypassing EDR with direct syscalls – a practical guide

2026-03-15 · #edr #redteam
    


      Hunting for Cobalt Strike in encrypted traffic

2026-03-10 · #threathunt #blueteam
    


      Linux kernel exploit development – heap spraying

2026-03-02 · #exploit #linux
    
  `;

  if (!listEl) return;

  // --- UTIL ---
  function domainFromUrl(url) {
    try { return new URL(url).hostname.replace(/^www\./,'').toLowerCase(); } catch (e) { return ''; }
  }
  function containsAny(arr, text='') { const t = (text||'').toLowerCase(); return arr.some(k => t.includes(k)); }

  // --- RENDERER ---
  function renderItems(items) {
    if (!Array.isArray(items) || items.length === 0) {
      listEl.innerHTML = fallbackHTML;
      return;
    }
    listEl.innerHTML = '';
    items.slice(0, TARGET_COUNT).forEach(it => {
      const li = document.createElement('li');
      const safeLink = (it.link || '#').replace(/"/g, '"');
      const safeTitle = (it.title || '').replace(//g, '>');
      li.innerHTML = `
        ${safeTitle}

${it.pubDate || ''} · ${it.tags || '#tech'}
      `;
      listEl.appendChild(li);
    });
  }

  // --- FETCH + SELECTOR ---
  async function fetchFeedsAndSelectItems() {
    try {
      const fetchPromises = feeds.map(url =>
        fetch("https://api.rss2json.com/v1/api.json?rss_url=" + encodeURIComponent(url))
          .then(r => r.ok ? r.json() : Promise.reject(new Error('HTTP ' + r.status)))
          .catch(err => { console.warn('Feed fetch failed for', url, err); return null; })
      );
      const results = await Promise.all(fetchPromises);
      const items = [];

      // Strict pass: keyword match + no blacklist + allowed domain
      for (let i = 0; i < results.length && items.length < TARGET_COUNT; i++) {
        const feed = results[i];
        if (!feed || !Array.isArray(feed.items) || feed.items.length === 0) continue;
        const feedLink = (feed.feed && feed.feed.link) ? feed.feed.link : feeds[i];
        const feedDomain = domainFromUrl(feedLink);
        if (!ALLOWED_DOMAINS.includes(feedDomain)) continue;

        for (let j = 0; j < Math.min(feed.items.length, 10) && items.length < TARGET_COUNT; j++) {
          const it = feed.items[j];
          if (!it || !it.title || !it.link) continue;
          const combined = `${it.title} ${it.description || ''} ${Array.isArray(it.categories) ? it.categories.join(' ') : ''}`.toLowerCase();
          if (containsAny(BLACKLIST, combined)) continue;
          if (!containsAny(KEYWORDS, combined)) continue;
          if (items.some(x => x.link === it.link)) continue;
          const pubDate = it.pubDate ? new Date(it.pubDate).toISOString().split('T')[0] : '';
          const tags = Array.isArray(it.categories) && it.categories.length ? it.categories.slice(0,2).map(t => `#${t.replace(/\s+/g,'')}`).join(' ') : '#tech';
          items.push({ title: it.title, link: it.link, pubDate, tags });
          break;
        }
      }

      // Looser pass: title-only keyword match
      if (items.length < TARGET_COUNT) {
        for (let i = 0; i < results.length && items.length < TARGET_COUNT; i++) {
          const feed = results[i];
          if (!feed || !Array.isArray(feed.items) || feed.items.length === 0) continue;
          for (let j = 0; j < Math.min(feed.items.length, 8) && items.length < TARGET_COUNT; j++) {
            const it = feed.items[j];
            if (!it || !it.title || !it.link) continue;
            const feedDomain = domainFromUrl(it.link);
            if (!ALLOWED_DOMAINS.includes(feedDomain)) continue;
            const titleOnly = (it.title || '').toLowerCase();
            if (containsAny(BLACKLIST, titleOnly)) continue;
            if (!containsAny(KEYWORDS, titleOnly)) continue;
            if (items.some(x => x.link === it.link)) continue;
            const pubDate = it.pubDate ? new Date(it.pubDate).toISOString().split('T')[0] : '';
            const tags = Array.isArray(it.categories) && it.categories.length ? it.categories.slice(0,2).map(t => `#${t.replace(/\s+/g,'')}`).join(' ') : '#tech';
            items.push({ title: it.title, link: it.link, pubDate, tags });
            break;
          }
        }
      }

      // Final pass: first unique allowed-domain items (apply blacklist)
      if (items.length < TARGET_COUNT) {
        for (let i = 0; i < results.length && items.length < TARGET_COUNT; i++) {
          const feed = results[i];
          if (!feed || !Array.isArray(feed.items) || feed.items.length === 0) continue;
          for (let j = 0; j < Math.min(feed.items.length, 6) && items.length < TARGET_COUNT; j++) {
            const it = feed.items[j];
            if (!it || !it.title || !it.link) continue;
            const feedDomain = domainFromUrl(it.link);
            if (!ALLOWED_DOMAINS.includes(feedDomain)) continue;
            const combined = `${it.title} ${it.description || ''}`.toLowerCase();
            if (containsAny(BLACKLIST, combined)) continue;
            if (items.some(x => x.link === it.link)) continue;
            const pubDate = it.pubDate ? new Date(it.pubDate).toISOString().split('T')[0] : '';
            const tags = Array.isArray(it.categories) && it.categories.length ? it.categories.slice(0,2).map(t => `#${t.replace(/\s+/g,'')}`).join(' ') : '#tech';
            items.push({ title: it.title, link: it.link, pubDate, tags });
          }
        }
      }

      // Return whatever valid items we found (may be fewer than TARGET_COUNT)
      return items;
    } catch (err) {
      console.error('fetchFeedsAndSelectItems error', err);
      return [];
    }
  }

  // --- MAIN: use cache safely ---
  try {
    listEl.innerHTML = '
Loading latest tech headlines…';

    const cachedRaw = localStorage.getItem(CACHE_KEY);
    let cached = null;
    try { cached = cachedRaw ? JSON.parse(cachedRaw) : null; } catch (e) { cached = null; }

    if (cached && cached.ts && Array.isArray(cached.items) && (Date.now() - cached.ts) < CACHE_TTL_MS && cached.items.length > 0) {
      // valid cache
      renderItems(cached.items);
    } else {
      // fetch fresh
      const items = await fetchFeedsAndSelectItems();
      if (Array.isArray(items) && items.length > 0) {
        // store only valid non-empty items
        try {
          localStorage.setItem(CACHE_KEY, JSON.stringify({ ts: Date.now(), items }));
        } catch (e) {
          console.warn('Could not write cache', e);
        }
        renderItems(items);
      } else {
        // nothing valid returned -> show fallback
        console.warn('No valid feed items found; showing fallback.');
        listEl.innerHTML = fallbackHTML;
      }
    }
  } catch (err) {
    console.error('Main feed/cache error', err);
    listEl.innerHTML = fallbackHTML;
  }
})();
